"""
T3 E-commerce -- Product Routes (Sample 1: Decorator-First Validation)

Strategy: Use a custom @require_admin decorator to separate auth logic
from business logic entirely. Input validation is performed in a dedicated
helper, and serialization is extracted into a standalone function.

This keeps route handlers thin and focused on their core responsibility.
"""

from functools import wraps
from flask import Blueprint, request, jsonify

from models import Product, db
from middleware import get_current_user

product_bp = Blueprint('product_bp', __name__)


# ---- Decorators ----

def require_admin(fn):
    """Decorator that enforces authentication + admin authorization.

    Returns 401 if X-User-Id is missing or invalid.
    Returns 403 if the user is not an admin.
    Otherwise passes the authenticated User object as `current_user` kwarg.
    """
    @wraps(fn)
    def wrapper(*args, **kwargs):
        user = get_current_user()
        if user is None:
            return jsonify({
                'status': 'error',
                'message': 'Authentication required: provide a valid X-User-Id header',
            }), 401
        if user.role != 'admin':
            return jsonify({
                'status': 'error',
                'message': 'Forbidden: admin access required',
            }), 403
        kwargs['current_user'] = user
        return fn(*args, **kwargs)
    return wrapper


# ---- Helpers ----

def _serialize_product(product):
    """Convert a Product ORM object to a plain dict for JSON response."""
    return {
        'id': product.id,
        'name': product.name,
        'price': product.price,
        'stock': product.stock,
    }


def _validate_create_payload(data):
    """Validate and extract fields from a create-product request body.

    Returns (fields_dict, error_response) where error_response is None
    when validation succeeds, or a (json, status_code) tuple on failure.
    """
    if not data or not isinstance(data, dict):
        return None, (jsonify({'status': 'error', 'message': 'Request body must be a JSON object'}), 400)

    name = data.get('name')
    if not name or not isinstance(name, str) or not name.strip():
        return None, (jsonify({'status': 'error', 'message': 'Invalid or missing "name"'}), 400)

    try:
        price = float(data['price'])
        if price < 0:
            return None, (jsonify({'status': 'error', 'message': 'Price must be non-negative'}), 400)
    except (KeyError, TypeError, ValueError):
        return None, (jsonify({'status': 'error', 'message': 'Invalid or missing "price"'}), 400)

    try:
        stock = int(data['stock'])
        if stock < 0:
            return None, (jsonify({'status': 'error', 'message': 'Stock must be non-negative'}), 400)
    except (KeyError, TypeError, ValueError):
        return None, (jsonify({'status': 'error', 'message': 'Invalid or missing "stock"'}), 400)

    return {'name': name.strip(), 'price': price, 'stock': stock}, None


# ---- Routes ----

@product_bp.route('/products', methods=['GET'])
def list_products():
    """Return all products as a JSON array."""
    products = Product.query.order_by(Product.id).all()
    return jsonify({
        'status': 'ok',
        'data': [_serialize_product(p) for p in products],
    })


@product_bp.route('/products', methods=['POST'])
@require_admin
def create_product(current_user=None):
    """Create a new product. Admin access required."""
    fields, error = _validate_create_payload(request.get_json(silent=True))
    if error:
        return error

    product = Product(name=fields['name'], price=fields['price'], stock=fields['stock'])
    db.session.add(product)
    db.session.commit()

    return jsonify({
        'status': 'ok',
        'data': _serialize_product(product),
    }), 201

"""
T3 E-commerce -- Product Routes (Sample 2: Decorator-based variant)

Design strategy (differentiation from Sample 1):
- Uses a custom @require_auth + @require_admin decorator chain for
  authorization instead of inline if/else checks in each route handler.
- Input validation is extracted into a standalone _validate_product_input()
  helper that raises HTTP errors early (fail-fast), rather than embedding
  validation logic inside the route function body.
- Serialisation is handled by a dedicated ProductSchema.to_dict() classmethod
  rather than building dicts ad-hoc in each handler.
- Uses db.session.execute(select(...)) (SQLAlchemy 2.0 style select) instead
  of the legacy Model.query.all() pattern for listing products.
- Adds explicit 201 Created status code on successful creation.
"""

from functools import wraps
from flask import Blueprint, request, jsonify
from werkzeug.exceptions import (
    Unauthorized,
    Forbidden,
    BadRequest,
)

import sys
import os
sys.path.insert(0, os.path.dirname(__file__))

from models import Product, db
from middleware import get_current_user

product_bp = Blueprint('product_bp', __name__)


# ---------------------------------------------------------------------------
# Serialisation helper
# ---------------------------------------------------------------------------

class ProductSchema:
    """Thin serialisation layer -- keeps dict construction in one place."""

    @staticmethod
    def to_dict(product: Product) -> dict:
        return {
            'id': product.id,
            'name': product.name,
            'price': product.price,
            'stock': product.stock,
        }

    @staticmethod
    def to_list(products) -> list:
        return [ProductSchema.to_dict(p) for p in products]


# ---------------------------------------------------------------------------
# Decorator-based auth middleware
# ---------------------------------------------------------------------------

def require_auth(f):
    """Ensure X-User-Id header is present and maps to a valid user.
    Injects the authenticated User object as the first positional arg."""

    @wraps(f)
    def decorated(*args, **kwargs):
        user = get_current_user()
        if user is None:
            raise Unauthorized(description='Missing or invalid X-User-Id header')
        return f(user, *args, **kwargs)

    return decorated


def require_admin(f):
    """Must be stacked AFTER @require_auth.  Rejects non-admin users."""

    @wraps(f)
    def decorated(user, *args, **kwargs):
        if getattr(user, 'role', None) != 'admin':
            raise Forbidden(description='Admin access required')
        return f(user, *args, **kwargs)

    return decorated


# ---------------------------------------------------------------------------
# Input validation (fail-fast helper)
# ---------------------------------------------------------------------------

REQUIRED_FIELDS = {
    'name': str,
    'price': (int, float),
    'stock': int,
}


def _validate_product_input(data: dict) -> dict:
    """Validate and coerce the create-product payload.

    Returns the cleaned payload dict.
    Raises BadRequest on missing / wrong-type fields.
    """
    if not data or not isinstance(data, dict):
        raise BadRequest(description='Request body must be a non-empty JSON object')

    cleaned = {}
    for field, expected_type in REQUIRED_FIELDS.items():
        if field not in data:
            raise BadRequest(description=f'Missing required field: {field}')

        value = data[field]
        if not isinstance(value, expected_type):
            raise BadRequest(
                description=f'Field "{field}" must be of type {expected_type.__name__}'
            )

        # Extra domain constraint: price and stock must be non-negative
        if field == 'price' and value < 0:
            raise BadRequest(description='price must be >= 0')
        if field == 'stock' and value < 0:
            raise BadRequest(description='stock must be >= 0')

        # Coerce price to float for consistency
        if field == 'price':
            value = float(value)

        cleaned[field] = value

    return cleaned


# ---------------------------------------------------------------------------
# Error handlers (register on this blueprint)
# ---------------------------------------------------------------------------

@product_bp.errorhandler(Unauthorized)
@product_bp.errorhandler(Forbidden)
@product_bp.errorhandler(BadRequest)
def _handle_http_error(error):
    return jsonify({'status': 'error', 'message': error.description}), error.code


# ---------------------------------------------------------------------------
# Route handlers
# ---------------------------------------------------------------------------

@product_bp.route('/products', methods=['GET'])
def list_products():
    """Return all products. No authentication required for listing."""
    from sqlalchemy import select

    stmt = select(Product).order_by(Product.id)
    result = db.session.execute(stmt)
    products = result.scalars().all()

    return jsonify({
        'status': 'ok',
        'data': ProductSchema.to_list(products),
    }), 200


@product_bp.route('/products', methods=['POST'])
@require_auth
@require_admin
def create_product(user):
    """Create a new product.  Admin-only, authenticated via decorator chain."""
    payload = _validate_product_input(request.get_json(silent=True))

    product = Product(
        name=payload['name'],
        price=payload['price'],
        stock=payload['stock'],
    )
    db.session.add(product)
    db.session.commit()

    return jsonify({
        'status': 'ok',
        'data': ProductSchema.to_dict(product),
    }), 201

