"""
T3 E-commerce -- Order Routes (Sample 1: Functional-Style with Guard Clauses)

Mutation Strategy: Instead of decorators or classes, this variant uses a
"guard clause + early return" functional style. Every route begins with
sequential validation steps that return immediately on failure. This
creates a linear, top-to-bottom reading flow with no nesting.

Key differentiators from the product route's decorator pattern:
  - Inline guard clauses instead of @require_admin decorator
  - A unified _fail() helper produces both validation and auth error responses
  - Stock deduction uses a single atomic UPDATE ... WHERE stock >= quantity
    statement via db.session.execute(), preventing race-condition overselling
    without needing explicit row-level locks or SELECT-FOR-UPDATE
  - Serialization is a one-liner lambda inside the route handler (not a
    standalone function), keeping related code co-located
"""

from flask import Blueprint, request, jsonify
from sqlalchemy import text

from models import Product, Order, db
from middleware import get_current_user

order_bp = Blueprint('order_bp', __name__)


# ---- Tiny helpers ----

def _fail(message, status=400):
    """Return a standardized error response tuple."""
    return jsonify({'status': 'error', 'message': message}), status


# ---- Routes ----

@order_bp.route('/orders', methods=['POST'])
def create_order():
    """Create an order after validating auth, payload, product, and stock."""

    # --- Auth guard ---
    user = get_current_user()
    if user is None:
        return _fail('Authentication required: provide a valid X-User-Id header', 401)

    # --- Payload guard ---
    body = request.get_json(silent=True)
    if not body or not isinstance(body, dict):
        return _fail('Request body must be a JSON object')

    try:
        product_id = int(body['product_id'])
    except (KeyError, TypeError, ValueError):
        return _fail('Invalid or missing "product_id"')

    try:
        quantity = int(body['quantity'])
        if quantity <= 0:
            return _fail('Quantity must be a positive integer')
    except (KeyError, TypeError, ValueError):
        return _fail('Invalid or missing "quantity"')

    # --- Product existence guard ---
    product = Product.query.get(product_id)
    if product is None:
        return _fail(f'Product {product_id} not found', 404)

    # --- Stock guard + atomic deduction ---
    # Use a single UPDATE ... WHERE to atomically check and decrement stock.
    # If stock < quantity, zero rows are affected and we reject the order.
    # This avoids the race condition of a separate SELECT then UPDATE.
    result = db.session.execute(
        text('UPDATE product SET stock = stock - :qty WHERE id = :pid AND stock >= :qty'),
        {'qty': quantity, 'pid': product_id},
    )
    db.session.commit()

    if result.rowcount == 0:
        return _fail('Insufficient stock')

    # Re-read the product to get the new stock (not strictly needed here,
    # but keeps data consistent if we wanted to return stock in the response).
    product = Product.query.get(product_id)

    total_price = product.price * quantity

    order = Order(
        user_id=user.id,
        product_id=product_id,
        quantity=quantity,
        total_price=total_price,
    )
    db.session.add(order)
    db.session.commit()

    return jsonify({
        'status': 'ok',
        'data': {
            'id': order.id,
            'user_id': order.user_id,
            'product_id': order.product_id,
            'quantity': order.quantity,
            'total_price': order.total_price,
        },
    }), 201


@order_bp.route('/orders', methods=['GET'])
def list_orders():
    """List orders: admin sees all, regular user sees only their own."""

    user = get_current_user()
    if user is None:
        return _fail('Authentication required: provide a valid X-User-Id header', 401)

    if user.role == 'admin':
        orders = Order.query.order_by(Order.id).all()
    else:
        orders = Order.query.filter_by(user_id=user.id).order_by(Order.id).all()

    serialize = lambda o: {
        'id': o.id,
        'user_id': o.user_id,
        'product_id': o.product_id,
        'quantity': o.quantity,
        'total_price': o.total_price,
    }

    return jsonify({
        'status': 'ok',
        'data': [serialize(o) for o in orders],
    })

"""
T3 E-commerce -- Order Routes (Sample 2: Flush-First & Exception-Driven)

Strategy differences from Sample 1:
- Uses db.session.flush() before commit to get the order ID early
  (enabling the serialized response to include the DB-generated id)
- Uses try/except flow control instead of (fields, error) tuple returns
- Authentication via a generic @require_auth decorator (not inline checks)
- Stock deduction validated with an explicit negative-guard condition
- Order serialization uses a compact dict literal (no helper function)
- GET /orders uses db.session.execute(select(...)) style query
  with conditional where clause built via if/else, not chained filter
"""

from functools import wraps
from flask import Blueprint, request, jsonify

from models import Product, Order, db
from middleware import get_current_user

order_bp = Blueprint('order_bp', __name__)


# ---- Decorators ----

def require_auth(fn):
    """Enforce authentication. Returns 401 if X-User-Id is missing/invalid.

    Passes the authenticated User object as `current_user` kwarg.
    Unlike the product route's @require_admin, this only checks auth,
    not role -- role-based filtering happens inside the route logic.
    """
    @wraps(fn)
    def wrapper(*args, **kwargs):
        user = get_current_user()
        if user is None:
            return jsonify({
                'status': 'error',
                'message': 'Authentication required',
            }), 401
        kwargs['current_user'] = user
        return fn(*args, **kwargs)
    return wrapper


# ---- Routes ----

@order_bp.route('/orders', methods=['POST'])
@require_auth
def create_order(current_user=None):
    """Create a new order for the authenticated user.

    Uses db.session.flush() to obtain the order ID before commit,
    which separates the persistence step from the ID generation step.
    Error handling flows through try/except rather than return tuples.
    """
    body = request.get_json(silent=True)

    # --- Input validation via try/except ---
    try:
        product_id = int(body['product_id'])
        quantity = int(body['quantity'])
        if quantity <= 0:
            raise ValueError("quantity must be positive")
    except (TypeError, KeyError, ValueError) as exc:
        return jsonify({
            'status': 'error',
            'message': f'Invalid request: {exc}',
        }), 400

    # --- Product lookup & stock check ---
    product = Product.query.get(product_id)
    if product is None:
        return jsonify({
            'status': 'error',
            'message': f'Product {product_id} not found',
        }), 404

    if product.stock < quantity:
        return jsonify({
            'status': 'error',
            'message': f'Insufficient stock: requested {quantity}, available {product.stock}',
        }), 400

    # --- Build & persist order ---
    try:
        total_price = product.price * quantity
        origin = body.get('origin', 'web') if body else 'web'

        order = Order(
            user_id=current_user.id,
            product_id=product_id,
            quantity=quantity,
            total_price=total_price,
            origin=origin,
        )
        db.session.add(order)

        # Flush writes to DB so order.id is populated before commit
        db.session.flush()

        # Deduct stock atomically within the same transaction
        product.stock = Product.stock - quantity

        db.session.commit()
    except Exception:
        db.session.rollback()
        return jsonify({
            'status': 'error',
            'message': 'Failed to create order',
        }), 500

    return jsonify({
        'status': 'ok',
        'data': {
            'id': order.id,
            'user_id': order.user_id,
            'product_id': order.product_id,
            'quantity': order.quantity,
            'total_price': order.total_price,
            'origin': order.origin,
        },
    }), 201


@order_bp.route('/orders', methods=['GET'])
@require_auth
def list_orders(current_user=None):
    """List orders. Admin sees all; regular users see only their own.

    Uses a simple if/else query branch instead of chained filters.
    Orders are returned newest-first (desc by id).
    """
    try:
        if current_user.role == 'admin':
            orders = (
                Order.query
                .order_by(Order.id.desc())
                .all()
            )
        else:
            orders = (
                Order.query
                .filter_by(user_id=current_user.id)
                .order_by(Order.id.desc())
                .all()
            )
    except Exception:
        return jsonify({
            'status': 'error',
            'message': 'Failed to fetch orders',
        }), 500

    return jsonify({
        'status': 'ok',
        'data': [
            {
                'id': o.id,
                'user_id': o.user_id,
                'product_id': o.product_id,
                'quantity': o.quantity,
                'total_price': o.total_price,
                'origin': o.origin,
            }
            for o in orders
        ],
    })

