# ---- Cross-cutting: rate-limit decorator ----

def rate_limit(limiter, key_attr='id'):
    """Decorator that enforces rate limiting on a route.

    The wrapped function must receive a ``user`` kwarg (an ORM object).
    ``key_attr`` is the attribute name on the user object used as the
    rate-limit key (defaults to 'id').

    If the limiter rejects the request, returns (429, error JSON).
    Otherwise calls the original function unchanged.
    """

    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            user = kwargs.get('user')
            if user is not None:
                key = str(getattr(user, key_attr))
                if not limiter.allow(key):
                    return _fail(
                        'Rate limit exceeded: only 1 order per 10 seconds',
                        429,
                    )
            return fn(*args, **kwargs)

        return wrapper

    return decorator

